import { Tasks } from 'wasp/server/crud'

export const createTask: Tasks.CreateAction = async (args, context) => {
  const { description, isDone } = args.data

  // Append " [NEW]" to the description before saving
  const task = await context.entities.Task.create({
    data: {
      description: description + ' [NEW]',
      isDone: isDone ?? false
    }
  })

  return task
}

