      isDone: isDone ?? false
    }
  })

  return task
}

import { useState } from 'react'
import { Tasks } from 'wasp/client/crud'
import './Main.css'

export function MainPage() {
  const [description, setDescription] = useState('')

  const { data: tasks, isLoading, refetch } = Tasks.getAll.useQuery()
  const { create, isLoading: isCreating } = Tasks.create.useAction()

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!description.trim()) return

    await create({
      data: {
        description,
        isDone: false
      }
    })

    setDescription('')
    await refetch()
  }

  const toggleTaskDone = async (taskId: number, currentIsDone: boolean) => {
    // Note: We don't have an update operation configured, so this is a placeholder
    // In a real app, you'd want to add the update operation to the crud declaration
    console.log('Toggle task:', taskId, 'to', !currentIsDone)
  }

  return (
    <main className="container">
      <h2 className="title">Task Manager with CRUD Override</h2>

      <div className="task-form-container">
        <form onSubmit={handleSubmit} className="task-form">
          <input
            type="text"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Enter task description..."
            className="task-input"
            disabled={isCreating}
          />
          <button
            type="submit"
            className="button button-filled"
            disabled={isCreating || !description.trim()}
          >
            {isCreating ? 'Creating...' : 'Add Task'}
          </button>
        </form>
      </div>

      <div className="tasks-container">
        <h3>Tasks</h3>
        {isLoading ? (
          <p>Loading tasks...</p>
        ) : tasks && tasks.length > 0 ? (
          <ul className="task-list">
            {tasks.map((task) => (
              <li key={task.id} className="task-item">
                <input
                  type="checkbox"
                  checked={task.isDone}
                  onChange={() => toggleTaskDone(task.id, task.isDone)}
                  className="task-checkbox"
                />
                <span className={`task-description ${task.isDone ? 'done' : ''}`}>
                  {task.description}
                </span>
              </li>
            ))}
          </ul>
        ) : (
          <p className="empty-state">No tasks yet. Create one above!</p>
        )}
      </div>

      <div className="info-box">
        <p className="info-text">
          <strong>Note:</strong> All task descriptions will have " [NEW]" appended automatically
          by the custom create override function.
        </p>
      </div>
    </main>
  )
}

