/* Task Manager Styles */
.task-form-container {
  width: 100%;
  margin-bottom: 2rem;
}

.task-form {
  display: flex;
  gap: 1rem;
  width: 100%;
  max-width: 600px;
  margin: 0 auto;
}

.task-input {
  flex: 1;
  padding: 1rem;
  font-size: 1rem;
  border: 2px solid #ffcc00;
  border-radius: 10px;
  background: white;
}

.task-input:focus {
  outline: none;
  border-color: #e5b800;
}

.tasks-container {
  width: 100%;
  max-width: 600px;
  margin: 2rem auto;
  text-align: left;
}

.tasks-container h3 {
  font-size: 1.5rem;
  margin-bottom: 1rem;
  text-align: center;
}

.task-list {
  list-style: none;
  padding: 0;
}

.task-item {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 1rem;
  margin-bottom: 0.5rem;
  background: white;
  border: 2px solid #ffcc0044;
  border-radius: 10px;
}

.task-checkbox {
  width: 20px;
  height: 20px;
  cursor: pointer;
}

.task-description {
  flex: 1;
  font-size: 1.1rem;
}

.task-description.done {
  text-decoration: line-through;
  opacity: 0.6;
}

.empty-state {
  text-align: center;
  opacity: 0.6;
  font-style: italic;
}

.info-box {
  margin-top: 2rem;
  padding: 1rem;
  background: #ffcc0044;
  border-radius: 10px;
  border: 2px solid #ffcc00;
  max-width: 600px;
}

.info-text {
  font-size: 0.9rem;
  line-height: 1.5;
}

.button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

