},
);
```
…
```
app
.addRoute("operations", "tasks", {
path: "/tasks",
auth: false
})
.addCrud("crud", "tasks", {
entity: "Task",
create: { override: true },
getAll: { override: true }
});
```
…
#### Output
This configures all the standard CRUD operations, with function overrides for the `get`, `getAll` and `create` operations.
CRUD operations are a special case, with all overridden functions being exported from `src/features/crud/server/cruds/tasks.ts`.
