#### 自定义CRUD操作
虽然Wasp提供了默认实现，但你也可以轻松覆盖特定操作：
```
// src/taskOperations.ts
import { type TaskCrud } from 'wasp/server/crud'
import { type Task } from 'wasp/entities'
import { HttpError } from 'wasp/server'
export const createTaskWithValidation: TaskCrud.CreateAction<
{ title: string; description?: string; dueDate?: Date },
Task
> = async (args, context) => {
if (!context.user) {
throw new HttpError(401, '未认证用户')
}
// 业务逻辑验证
if (!args.title.trim()) {
throw new HttpError(400, '任务标题不能为空')
}
if (args.dueDate && args.dueDate < new Date()) {
throw new HttpError(400, '截止日期不能是过去时间')
}
const { Task } = context.entities
return await Task.create({
data: {
title: args.title.trim(),
description: args.description,
dueDate: args.dueDate,
user: { connect: { id: context.user.id } }
}
})
```

